"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[8071],{28453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>o});var i=n(96540);const r={},a=i.createContext(r);function s(e){const t=i.useContext(a);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:s(e.components),i.createElement(a.Provider,{value:t},e.children)}},31230:e=>{e.exports=JSON.parse('{"permalink":"/blog/how-did-we-end-up-here","editUrl":"https://github.com/DidierRLopes/my-website/tree/main/blog/2026-04-14-how-did-we-end-up-here.md","source":"@site/blog/2026-04-14-how-did-we-end-up-here.md","title":"How did we end up here?","description":"The case for a firm-owned workspace in the age of AI.","date":"2026-04-14T00:00:00.000Z","tags":[{"inline":true,"label":"ai","permalink":"/blog/tags/ai"},{"inline":true,"label":"finance","permalink":"/blog/tags/finance"},{"inline":true,"label":"openbb","permalink":"/blog/tags/openbb"},{"inline":true,"label":"infrastructure","permalink":"/blog/tags/infrastructure"}],"readingTime":11.14,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"how-did-we-end-up-here","title":"How did we end up here?","date":"2026-04-14T00:00:00.000Z","image":"/blog/2026-04-14-how-did-we-end-up-here.webp","tags":["ai","finance","openbb","infrastructure"],"description":"The case for a firm-owned workspace in the age of AI.","hideSidebar":true},"unlisted":false,"prevItem":{"title":"15 reasons why Streamlit doesn\'t work for production","permalink":"/blog/15-reasons-why-streamlit-doesnt-work-for-production"},"nextItem":{"title":"APIs for Analytics, MCP for Point-in-Time Data","permalink":"/blog/apis-for-analytics-mcp-for-point-in-time-data"}}')},50784:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>d,contentTitle:()=>o,default:()=>h,frontMatter:()=>s,metadata:()=>i,toc:()=>l});var i=n(31230),r=n(74848),a=n(28453);const s={slug:"how-did-we-end-up-here",title:"How did we end up here?",date:new Date("2026-04-14T00:00:00.000Z"),image:"/blog/2026-04-14-how-did-we-end-up-here.webp",tags:["ai","finance","openbb","infrastructure"],description:"The case for a firm-owned workspace in the age of AI.",hideSidebar:!0},o=void 0,d={authorsImageUrls:[]},l=[{value:"Workflows happen on vendor infrastructure",id:"workflows-happen-on-vendor-infrastructure",level:2},{value:"No single vendor covers the full data universe",id:"no-single-vendor-covers-the-full-data-universe",level:2},{value:"Internal data lacks first-class status",id:"internal-data-lacks-first-class-status",level:2},{value:"Business logic embeds in vendor platforms",id:"business-logic-embeds-in-vendor-platforms",level:2},{value:"API-level integration shifts the burden to the firm",id:"api-level-integration-shifts-the-burden-to-the-firm",level:2},{value:"Point solutions proliferate",id:"point-solutions-proliferate",level:2},{value:"AI embeds separately across every system",id:"ai-embeds-separately-across-every-system",level:2},{value:"Third-party AI chat interfaces centralize control further",id:"third-party-ai-chat-interfaces-centralize-control-further",level:2},{value:"It doesn&#39;t have to be this way",id:"it-doesnt-have-to-be-this-way",level:2}];function c(e){const t={a:"a",em:"em",h2:"h2",li:"li",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.p,{children:"The case for a firm-owned workspace in the age of AI."}),"\n",(0,r.jsx)(t.p,{children:"A few weeks ago we had a presentation for AITEC members where we showed what's possible on OpenBB today. Before jumping into the demo, I wanted to contextualize how OpenBB became OpenBB."}),"\n",(0,r.jsx)(t.p,{children:"So I created a presentation that walked through the journey shaping our product, our roadmap, and ultimately my/our world view."}),"\n",(0,r.jsx)(t.p,{children:"This post is an attempt to criticize where we are as an industry and why I believe we can do more."}),"\n",(0,r.jsx)(t.p,{children:(0,r.jsx)(t.strong,{children:"Financial firms should own the infrastructure where financial work happens."})}),"\n",(0,r.jsx)(t.p,{children:"I don't think that's a crazy statement. Yet we are very far from this reality."}),"\n",(0,r.jsx)(t.p,{children:"By infrastructure, I don't mean just the UI or just the data. I mean the runtime. Where workflows execute and where AI inference happens."}),"\n",(0,r.jsx)(t.p,{children:"This argument isn't anti-vendor. Vendors are essential. They generate and distribute rights-controlled market data. They ship analytics. They package workflows. The problem is what happens when the center of gravity of financial work lives on vendor infrastructure. Control boundaries blur. Internal context becomes second-class."}),"\n",(0,r.jsx)(t.p,{children:"Vendor data is the main incentive. Business logic becomes coupled to someone else's platform decisions."}),"\n",(0,r.jsxs)(t.p,{children:["The ",(0,r.jsx)(t.a,{href:"https://portageinvest.com/wp-content/uploads/2026/02/AI-Disruption-of-Financial-Services-Data-A-Portage-Perspective.pdf",children:"Portage thesis report"})," (",(0,r.jsx)(t.em,{children:"AI Disruption of the Financial Services Data Industry"}),") describes financial services as a uniquely idiosyncratic data environment where firms must mesh internal and external data across a complex and poorly documented web. It frames the current era as one of data abundance but insight scarcity. It also highlights the switching costs tied to entitlements, identifier dependencies, audit requirements, and downstream links. These are the mechanics of lock-in that show up as \"we can't move, and we can't unify\"."]}),"\n",(0,r.jsx)(t.p,{children:'The conclusion is not "build everything yourself". It is: build or adopt the platform layer that keeps data, workflows, and AI inference inside a governed enterprise boundary, while remaining neutral to vendors and modular to change.'}),"\n",(0,r.jsx)(t.p,{children:"This essay follows my thinking process of what's wrong today, which ultimately leads to the vision of what OpenBB Workspace is, and isn't."}),"\n",(0,r.jsx)(t.p,{children:"You own the interface where financial work happens. Data flows in. Intelligence runs inside. Your workflows are yours."}),"\n",(0,r.jsx)(t.p,{children:"The bottleneck in modern finance is not the raw presence of data. It's the ability to turn overwhelming volume into usable decision-grade information. \"Owning the interface\" is shorthand for owning the place where context lives, where governance is enforced, and where the firm's proprietary understanding becomes reusable. If the workflow runtime is yours, internal context (positions, models, research, constraints, entitlements) can be treated as a first-class citizen. And so can anything else you wish to bring in."}),"\n",(0,r.jsx)(t.p,{children:"AI accelerates this massively. Modern AI tooling is the first credible opportunity to simplify financial data access at scale, including by generating glue code across disparate formats and improving data quality continuously rather than diagnostically. Portage makes this argument explicitly. But it only compounds into durable advantage if the firm controls the environment where the simplification occurs."}),"\n",(0,r.jsx)(t.p,{children:(0,r.jsx)(t.strong,{children:"But this is not where we are today."})}),"\n",(0,r.jsx)(t.h2,{id:"workflows-happen-on-vendor-infrastructure",children:"Workflows happen on vendor infrastructure"}),"\n",(0,r.jsx)(t.p,{children:"When user activity, data queries, and workflow execution happen in vendor-managed environments, the firm gets productivity but yields sovereignty. The logging depth, runtime controls, operational policy, and evidence production are bounded by what the provider exposes."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_1.webp",alt:"Workflows happening on vendor infrastructure"})}),"\n",(0,r.jsx)(t.h2,{id:"no-single-vendor-covers-the-full-data-universe",children:"No single vendor covers the full data universe"}),"\n",(0,r.jsx)(t.p,{children:"Equities, credit, macro, alternatives, and proprietary datasets come from different providers. Portage describes this universe as inherently diverse, spanning raw data generators, distributors, and analytic layers, with delivery mechanisms that range from feeds and APIs to terminals to cloud channels. So analysts and PMs stitch context across disconnected platforms to assemble a coherent view."}),"\n",(0,r.jsx)(t.p,{children:"Fragmentation isn't just inconvenient. It breaks repeatability. Once workflows cross tool boundaries, intermediate assumptions and transformations become invisible or non-portable. That invisibility is a form of risk: you can't govern what you can't observe."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_2.webp",alt:"No single vendor covers the full data universe"})}),"\n",(0,r.jsx)(t.h2,{id:"internal-data-lacks-first-class-status",children:"Internal data lacks first-class status"}),"\n",(0,r.jsxs)(t.p,{children:["Uploading portfolios, proprietary datasets, or internal research is harder than it should be. Not because it's technologically hard, but because vendor platforms are optimized around vendor-controlled universes. Their incentives are the data margins. I wrote more about this ",(0,r.jsx)(t.a,{href:"https://didierlopes.com/blog/the-hidden-incentive-war-behind-financial-terminals",children:"here"}),"."]}),"\n",(0,r.jsx)(t.p,{children:"The firm's edge is not the vendor dataset. It is the firm's ability to combine vendor inputs with internal context. When internal data can't sit natively inside the same workspace, you end up with two realities: the vendor's (shared with every other firm) and your own (fully detached). Your reality is the one that matters. But when you're forced to model your world view through what a vendor provides, you hit limits in what you can do."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_3.webp",alt:"Internal data lacks first-class status in vendor platforms"})}),"\n",(0,r.jsx)(t.h2,{id:"business-logic-embeds-in-vendor-platforms",children:"Business logic embeds in vendor platforms"}),"\n",(0,r.jsx)(t.p,{children:'Even when vendors are flexible, they ship a worldview: how data is mapped, what analytics are "standard", what a research workflow looks like, what gets logged, what gets shared. Firms operate within those constraints to remain compatible with the platform.'}),"\n",(0,r.jsx)(t.p,{children:"Portage's framing of the value chain shows how value accrues from rights-controlled sourcing through processing and analytics to distribution, where outputs get embedded in workflows. When workflow embedding is owned by the vendor, those dependencies become procedural and cultural. Portage also calls out the concrete mechanics that raise replacement costs: entitlements and data rights, identifier dependencies, audit requirements, and established links downstream."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_4.webp",alt:"Business logic embeds in vendor platforms"})}),"\n",(0,r.jsx)(t.h2,{id:"api-level-integration-shifts-the-burden-to-the-firm",children:"API-level integration shifts the burden to the firm"}),"\n",(0,r.jsx)(t.p,{children:"This is the cumulative picture. Multiple data vendors, each running their own infrastructure, each with their own financial workspace, each sending usage data back."}),"\n",(0,r.jsx)(t.p,{children:"Your firm sits at the edge, receiving outputs from disconnected systems."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_5.webp",alt:"Multiple data vendors with disconnected infrastructure"})}),"\n",(0,r.jsx)("br",{}),"\n",(0,r.jsx)(t.p,{children:"When the vendor platform can't be the workspace for the entire firm, the natural reaction is to consume vendor data as raw input and rebuild workflows internally."}),"\n",(0,r.jsx)(t.p,{children:"Portage's investment thesis emphasizes developer-friendly APIs and distribution layers as where new winners will serve data and insights. That is the direction of travel. The terminal becomes less central. The enterprise integration layer becomes more central."}),"\n",(0,r.jsx)(t.p,{children:"But API rebuilding moves the burden. Integration, governance, lifecycle management, entitlement enforcement, and auditability become the firm's job again, often without the benefit of a unified platform."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_6.webp",alt:"API-level integration shifts burden to the firm"})}),"\n",(0,r.jsx)(t.h2,{id:"point-solutions-proliferate",children:"Point solutions proliferate"}),"\n",(0,r.jsx)(t.p,{children:"Once you start rebuilding from APIs, teams solve local pain fast. Portfolio tools, research dashboards, risk widgets, internal apps. Each gap gets patched. Each introduces its own stack, access controls, and operational overhead."}),"\n",(0,r.jsx)(t.p,{children:"Portage notes that supporting layers like platform development, provenance, entitlements, and cloud delivery determine which point solutions can scale into standards. When those layers are absent or inconsistent, point solutions proliferate but none of them become shared infrastructure."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_7.webp",alt:"Point solutions proliferate across the firm"})}),"\n",(0,r.jsx)(t.h2,{id:"ai-embeds-separately-across-every-system",children:"AI embeds separately across every system"}),"\n",(0,r.jsx)(t.p,{children:"Now the stack expands again. Each internal application integrates its own LLM provider, retrieval pipeline, prompt logic, and cost policy. Model governance becomes distributed across every app, with no central oversight."}),"\n",(0,r.jsx)(t.p,{children:"If you implement AI as scattered per-app integrations, the governance functions that matter (model versioning, prompt auditing, retrieval policies, tool permissions) become nearly impossible to execute uniformly."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_8.webp",alt:"AI embeds separately across every system"})}),"\n",(0,r.jsx)(t.h2,{id:"third-party-ai-chat-interfaces-centralize-control-further",children:"Third-party AI chat interfaces centralize control further"}),"\n",(0,r.jsx)(t.p,{children:"New entrants provide proprietary chat interfaces that sit above your systems. The firm now integrates and governs yet another vendor, often by uploading data that already exists elsewhere: internal research, portfolios, board materials, or licensed market data."}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_9.webp",alt:"Third-party AI chat interfaces centralize control further"})}),"\n",(0,r.jsx)("br",{}),"\n",(0,r.jsx)(t.p,{children:"This creates two compounding problems."}),"\n",(0,r.jsx)(t.p,{children:"First, if you upload licensed data into a third-party AI environment, you must be able to defend that it remains within permitted use, and you must prove entitlements and control propagation. That is difficult without a firm-owned policy and logging plane. Exchange policy documents restrict redistribution. A firm that uploads licensed feeds into an uncontrolled UI is creating a defensibility problem it may not be able to unwind."}),"\n",(0,r.jsx)(t.p,{children:"Second, regulatory-grade auditability is easier when inference is inside your governed runtime. Even if a provider doesn't log prompts, the firm still needs its own evidence. Who accessed what, what context was used, what output influenced what artifact, and how retention applies. Especially under record-keeping regimes that emphasize audit trails and producibility."}),"\n",(0,r.jsx)(t.p,{children:"What we have built as an industry is not one stack. It is multiple stacks stitched together. Each with its own entitlements, its own logging, its own identity, its own policy logic."}),"\n",(0,r.jsx)(t.p,{children:"And AI pours gasoline on that fragmentation."}),"\n",(0,r.jsx)(t.h2,{id:"it-doesnt-have-to-be-this-way",children:"It doesn't have to be this way"}),"\n",(0,r.jsx)(t.p,{children:"But it doesn't have to be this way."}),"\n",(0,r.jsx)(t.p,{children:"Consolidate vendor data, proprietary datasets, internal apps, and AI into a single governed environment. Nothing leaves your infrastructure, including model inference."}),"\n",(0,r.jsx)(t.p,{children:'Now the concrete "how".'}),"\n",(0,r.jsx)("p",{align:"center",children:(0,r.jsx)("img",{width:"800",src:"/blog/2026-04-14-how-did-we-end-up-here_10.webp",alt:"Consolidated firm-owned workspace architecture"})}),"\n",(0,r.jsx)("br",{}),"\n",(0,r.jsx)(t.p,{children:"A platform architecture that keeps firms sovereign. At the core is a simple separation: vendors provide inputs (raw data, analytics, or inference like LLMs). The firm owns the workspace where decisions are made. And the workspace has no external context by default."}),"\n",(0,r.jsx)(t.p,{children:"The owned-runtime model in practice: vendor inputs flow in, internal data is native, workflows run inside a controlled environment, and AI inference is routed through a governed gateway that enforces policy and produces audit-grade telemetry."}),"\n",(0,r.jsx)(t.p,{children:"The components: internal systems and external vendors as data sources. A firm-controlled environment with SSO/identity, RBAC/ABAC and entitlements policy. A data substrate in open formats. A firm-owned semantic layer for IDs, mappings, and metrics. Firm-owned workflows (apps, dashboards, agents). A model gateway handling routing, quotas, and evals with a controlled inference runtime. Immutable audit trail and observability across logs, metrics, and traces."}),"\n",(0,r.jsx)(t.p,{children:"What flows through this: any market data (exchanges, filings, news, transcripts, alternatives), your portfolio positions (without uploading to third parties), third-party AI agent integrations, and your additional context (research, risk policy, signals)."}),"\n",(0,r.jsxs)(t.ul,{children:["\n",(0,r.jsxs)(t.li,{children:["\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"Control."})," SSO, RBAC, logs, and permissioning standardized across workflows. Alignment with modern security models and with record-keeping expectations that assume you can produce and prove what happened."]}),"\n"]}),"\n",(0,r.jsxs)(t.li,{children:["\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"Neutrality."})," Connect any data vendor without changing the interface layer. Neutrality becomes real when entitlements and identifiers are abstracted into a firm-owned semantic and policy layer. Portage notes that entitlements and identifier dependencies are what tie customers to incumbents. Open formats and vendor-neutral observability reduce lock-in at the storage and monitoring layers."]}),"\n"]}),"\n",(0,r.jsxs)(t.li,{children:["\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"Enterprise-ready."})," Apps and agents built by one team can be securely shared across the firm. Shared primitives, shared guardrails, shared operational standards. Without that, point solutions don't become products. They become liabilities."]}),"\n"]}),"\n",(0,r.jsxs)(t.li,{children:["\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"AI governance."})," Model orchestration, usage tracking, and inference policies managed centrally. Centralizing inference through a model gateway turns governance into something you can actually execute."]}),"\n"]}),"\n"]}),"\n",(0,r.jsx)("br",{}),"\n",(0,r.jsx)(t.p,{children:"If I had to reduce this into a practical, stack-agnostic set of actions:"}),"\n",(0,r.jsx)(t.p,{children:"Build a governed data substrate that supports both structured and unstructured inputs. Documents, transcripts, and other scarce unstructured sources need to live in the same environment as market feeds. If they don't, your AI can only reason over half your world-view."}),"\n",(0,r.jsx)(t.p,{children:"Favor open formats and decoupled compute so data remains portable and AI-enabled without rewriting your world."}),"\n",(0,r.jsx)(t.p,{children:"Implement entitlements, provenance, and identifier mapping as first-class platform services. These are the mechanics that create lock-in. If this logic lives inside every app, you will never become vendor-neutral."}),"\n",(0,r.jsx)(t.p,{children:'Build immutable audit trails for the artifacts that matter (research notes, generated outputs that enter a workflow, approvals, exports) and keep the link from "who asked" to "what data was accessed" to "what output was produced."'}),"\n",(0,r.jsx)(t.p,{children:"Treat third-party AI chat interfaces as edges, not centers. Use them through governance boundaries. Where external AI must be used, rely on enterprise configurations that support constraints like non-training by default and optional zero retention. But keep the firm's own logs and policies as the source of truth."}),"\n",(0,r.jsx)(t.p,{children:"And if you want an infrastructure kickstart for this journey, reach out to me. We know a thing or two."})]})}function h(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(c,{...e})}):c(e)}}}]);